(async () => {
  const results = {
    url: VERIFY_URL,
    timestamp: new Date().toISOString(),
    summary: { total: 0, pass: 0, fail: 0 },
    steps: [],
  };

  const screenshotDir = path.join(VERIFY_OUT, 'screenshots');
  fs.mkdirSync(screenshotDir, { recursive: true });

  const browser = await chromium.launch({ headless: true });
  const context = await browser.newContext({ ignoreHTTPSErrors: true });
  const page = await context.newPage();

  const consoleErrors = [];
  page.on('console', msg => { if (msg.type() === 'error') consoleErrors.push(msg.text()); });

  function addStep(name, status, detail, screenshot) {
    results.summary.total++;
    if (status === 'pass') results.summary.pass++;
    else results.summary.fail++;
    results.steps.push({ name, status, detail, screenshot: screenshot || null, time: new Date().toISOString() });
